import{_ as t,c as n,o as i,a1 as a}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Plattformfunktionen | opencode-mystatus","description":"Lernen Sie die Kreditabfragefunktionen verschiedener KI-Plattformen kennen. opencode-mystatus unterstützt OpenAI, Zhipu AI, GitHub Copilot und Google Cloud.","frontmatter":{"title":"Plattformfunktionen | opencode-mystatus","sidebarTitle":"Plattformen","subtitle":"Plattformfunktionen","description":"Lernen Sie die Kreditabfragefunktionen verschiedener KI-Plattformen kennen. opencode-mystatus unterstützt OpenAI, Zhipu AI, GitHub Copilot und Google Cloud.","order":2},"headers":[],"relativePath":"de/vbgate/opencode-mystatus/platforms/index.md","filePath":"de/vbgate/opencode-mystatus/platforms/index.md"}'),r={name:"de/vbgate/opencode-mystatus/platforms/index.md"};function o(l,e,d,u,s,h){return i(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="plattformfunktionen" tabindex="-1">Plattformfunktionen <a class="header-anchor" href="#plattformfunktionen" aria-label="Permalink to &quot;Plattformfunktionen&quot;">​</a></h1><p>Dieses Kapitel beschreibt ausführlich die Kreditabfragefunktionen der verschiedenen KI-Plattformen, die von opencode-mystatus unterstützt werden.</p><h2 id="unterstutzte-plattformen" tabindex="-1">Unterstützte Plattformen <a class="header-anchor" href="#unterstutzte-plattformen" aria-label="Permalink to &quot;Unterstützte Plattformen&quot;">​</a></h2><p>opencode-mystatus unterstützt die folgenden 4 Haupt-KI-Plattformen:</p><table tabindex="0"><thead><tr><th>Plattform</th><th>Kreditart</th><th>Merkmale</th></tr></thead><tbody><tr><td>OpenAI</td><td>3 Stunden / 24 Stunden Schiebefenster</td><td>Unterstützt Plus, Team, Pro-Abonnements</td></tr><tr><td>Zhipu AI</td><td>5-Stunden-Token / MCP-monatliche Quote</td><td>Unterstützt Coding Plan</td></tr><tr><td>GitHub Copilot</td><td>Monatliche Quote</td><td>Zeigt Premium Requests-Nutzung</td></tr><tr><td>Google Cloud</td><td>Nach Modell berechnet</td><td>Unterstützt mehrere Konten, 4 Modelle</td></tr></tbody></table><h2 id="detaillierte-plattformbeschreibungen" tabindex="-1">Detaillierte Plattformbeschreibungen <a class="header-anchor" href="#detaillierte-plattformbeschreibungen" aria-label="Permalink to &quot;Detaillierte Plattformbeschreibungen&quot;">​</a></h2><h3 id="openai-kredit" tabindex="-1"><a href="./openai-usage/">OpenAI-Kredit</a> <a class="header-anchor" href="#openai-kredit" aria-label="Permalink to &quot;[OpenAI-Kredit](./openai-usage/)&quot;">​</a></h3><p>Erfahren Sie mehr über den Kreditabfrage-Mechanismus von OpenAI:</p><ul><li>Unterschied zwischen 3-Stunden- und 24-Stunden-Schiebefenstern</li><li>Kreditfreigabemechanismus von Teamkonten</li><li>JWT-Token-Analyse zum Abrufen von Kontoinformationen</li></ul><h3 id="zhipu-ai-kredit" tabindex="-1"><a href="./zhipu-usage/">Zhipu AI-Kredit</a> <a class="header-anchor" href="#zhipu-ai-kredit" aria-label="Permalink to &quot;[Zhipu AI-Kredit](./zhipu-usage/)&quot;">​</a></h3><p>Verstehen Sie die Kreditabfrage von Zhipu AI und Z.ai:</p><ul><li>Berechnungsweise des 5-Stunden-Token-Kredits</li><li>Verwendung der MCP-monatlichen Quote</li><li>Maskierte Anzeige des API-Keys</li></ul><h3 id="github-copilot-kredit" tabindex="-1"><a href="./copilot-usage/">GitHub Copilot-Kredit</a> <a class="header-anchor" href="#github-copilot-kredit" aria-label="Permalink to &quot;[GitHub Copilot-Kredit](./copilot-usage/)&quot;">​</a></h3><p>Meistern Sie die Kreditverwaltung von GitHub Copilot:</p><ul><li>Bedeutung von Premium Requests</li><li>Kreditunterschiede verschiedener Abonnementtypen</li><li>Berechnung der monatlichen Rücksetzzeit</li></ul><h3 id="google-cloud-kredit" tabindex="-1"><a href="./google-usage/">Google Cloud-Kredit</a> <a class="header-anchor" href="#google-cloud-kredit" aria-label="Permalink to &quot;[Google Cloud-Kredit](./google-usage/)&quot;">​</a></h3><p>Lernen Sie die Kreditabfrage von mehreren Google Cloud-Konten:</p><ul><li>Unterschiede zwischen den 4 Modellen (G3 Pro, G3 Image, G3 Flash, Claude)</li><li>Verwaltung und Wechsel mehrerer Konten</li><li>Mechanismus zum Lesen der Authentifizierungsdatei</li></ul><h2 id="auswahlleitfaden" tabindex="-1">Auswahlleitfaden <a class="header-anchor" href="#auswahlleitfaden" aria-label="Permalink to &quot;Auswahlleitfaden&quot;">​</a></h2><p>Wählen Sie je nach den verwendeten Plattformen das entsprechende Tutorial:</p><ul><li><strong>Nur OpenAI verwenden</strong>: Lesen Sie direkt <a href="./openai-usage/">OpenAI-Kredit</a></li><li><strong>Nur Zhipu AI verwenden</strong>: Lesen Sie direkt <a href="./zhipu-usage/">Zhipu AI-Kredit</a></li><li><strong>Multiplattform-Benutzer</strong>: Wir empfehlen, alle Plattformtutorials in Reihenfolge zu lesen</li><li><strong>Google Cloud-Benutzer</strong>: Sie müssen zuerst das <a href="https://github.com/NoeFabris/opencode-antigravity-auth" target="_blank" rel="noreferrer">opencode-antigravity-auth</a>-Plugin installieren</li></ul><h2 id="nachster-schritt" tabindex="-1">Nächster Schritt <a class="header-anchor" href="#nachster-schritt" aria-label="Permalink to &quot;Nächster Schritt&quot;">​</a></h2><p>Nach Abschluss dieses Kapitels können Sie mit <a href="./../advanced/">Erweiterte Funktionen</a> fortfahren, um weitere Konfigurationsoptionen kennenzulernen.</p>',23)])])}const f=t(r,[["render",o]]);export{p as __pageData,f as default};
